import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminSectionForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    Section_ID: '',
    Book_ID: '',
    Title_En: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getSectionById(id).then((res: any) => setFormData(res.data));
    }
  }, [id]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await AdminService.upsertSection(formData);
      toast.success("Section Synchronized");
      navigate('/admin/sections');
    } catch (err) { toast.error("Fault in system"); }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Back
      </button>

      <div className="bg-[#0f0f0f] p-10 rounded-[3rem] border border-white/5 shadow-xl">
        <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'Create'} <span className="text-primary">Section</span></h2>
        <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Section ID</label>
            <input value={formData.Section_ID} onChange={e => setFormData({...formData, Section_ID: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-white outline-none focus:border-primary" required disabled={!!id} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Parent Book ID</label>
            <input value={formData.Book_ID} onChange={e => setFormData({...formData, Book_ID: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-white outline-none focus:border-primary" required />
          </div>
          <div className="col-span-2 space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Title (English)</label>
            <input value={formData.Title_En} onChange={e => setFormData({...formData, Title_En: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-white outline-none focus:border-primary" required />
          </div>
          <button type="submit" className="col-span-2 bg-primary text-black font-black uppercase py-4 rounded-xl hover:bg-yellow-500 transition-all">Save Structure</button>
        </form>
      </div>
    </div>
  );
};
